const user = $input.all()[0]?.json;
const context = $('Contexto Mensaje').first().json;
const msg = (context.msg_body || "").trim().toLowerCase();

const user_exists = !!user?.qr_code;

let intent = "menu";
let sucursal = null;

const sucursalMatch = msg.match(/recargar?\s+cod(\d+)/i);
if (sucursalMatch) {
  intent = "recarga";
  sucursal = sucursalMatch[1];
} else if (/^\d{3}$/.test(msg)) {
  intent = "recarga";
  sucursal = msg;
} else if (msg === "recarga" || msg === "recargar") {
  // Si el usuario ya está registrado y tiene sucursal guardada, no pedirle el código de máquina
  const has_saved_sucursal = !!(user?.cred_sucursal || user?.user_sucursal);
  if (user_exists || has_saved_sucursal) {
    intent = "recarga";
  } else {
    intent = "recarga_invalida";
  }
} else if (msg.includes("saldo")) {
  intent = "saldo";
} else if (/^\d+$/.test(msg) && msg.length >= 4) {
  const active_sucursal = user?.cred_sucursal || user?.user_sucursal || sucursal;
  if (active_sucursal) {
    intent = "reference";
  } else { 
    intent = "recarga_invalida";
  }
} else {
  intent = "menu";
}

const active_sucursal = user?.cred_sucursal || user?.user_sucursal || sucursal;

return [{  json: {
    phone: context.phone,
    name: context.name || user?.first_name || 'Cliente',
    msg_body: context.msg_body,
    bot_phone: context.bot_phone,
    user_exists: user_exists,
    user_profile_exists: !!user,
    balance: parseInt(user?.saldo) || 0,
    qr_token: user?.qr_code || null,
    user_sucursal: user?.user_sucursal || null,
    active_sucursal: active_sucursal,
    sucursal_nombre: (user?.sucursal_nombre || 'Sucursal Principal').trim(),
    intent: intent
  }
}];

