const pgResult = $input.all();
const context = $('Evaluar Pago Pabilo').first().json;

if (pgResult.length === 0) {
  return [{
    json: {
      ...context,
      success: false,
      error_msg: 'Error interno en la base de datos al procesar la transacción. Por favor, intenta de nuevo.'
    }
  }];
}

if (!pgResult[0].json.payment_inserted) {
  return [{
    json: {
      ...context,
      success: false,
      error_msg: 'La referencia de pago ya ha sido utilizada anteriormente en este sistema.'
    }
  }];
}

return [{
  json: {
    ...context,
    success: true,
    qr_code_token: pgResult[0].json.qr_code_token,
    qr_token: pgResult[0].json.qr_code_token,
    balance: parseFloat(pgResult[0].json.balance),
    sucursal_nombre: (pgResult[0].json.sucursal_nombre || 'Sucursal Principal').trim()
  }
}];

